var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"사람 혼백을 먹는 세 마리 짐승이 있었다.","JPN":"人の魂魄を食らう3匹のケモノがいた。","ENG":"There were once Three Beasts that devoured human souls.","TWN":"有三隻吞食人類魂魄的野獸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"끝없는 굶주림에 시달리던 그것들은 이윽고 세상마저 삼키려 하였으니.","JPN":"果てしない飢えに苛まれていたそれらは、やがて世界をも呑み込もうとするも……","ENG":"Tormented by endless hunger, they eventually turned their eyes on the world itself.","TWN":"牠們飽受無盡的飢餓，最終試圖吞噬世界。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"세 명의 검객이 세 짐승의 목을 베고, 제일삼검이라 불리며 칭송 받았다.","JPN":"3人の剣士が3匹のケモノの首を切り落とし、三剣極と呼ばれ崇め称えられた。","ENG":"Three swordsmen rose and struck them down, severing their heads. They became known as the Three Blades.","TWN":"三名劍客斬斷了三隻野獸的頭顱，被譽為三軍第一劍客，備受讚揚。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만, 재앙은 한 세대가 채 지나기도 전에 다시 일어났다.","JPN":"しかし災害は1つの世代が終わるよりも前に再びやってきた。","ENG":"But the calamity returned in less than a generation.","TWN":"然而，災難在不到一代人的時間內再次降臨。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"짐승의 피가 흐른 땅에서 태어난 아이들의 영혼이 저주에 사로잡히고 만 것이다.","JPN":"ケモノが血を流した地で生まれた子どもの魂が、呪いにかかってしまったのだ。","ENG":"Children born on the cursed lands soaked in the Beast Blood found their souls seized by a dark curse.","TWN":"那些在野獸之血流淌的土地上誕生的孩子們，他們的靈魂被詛咒所困。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"땅내림.","JPN":"チガカリ。","ENG":"Earthbound.","TWN":"地脈之力。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"그 말 못할 저주로 아이들이 타고난 짐승의 피는 매 순간 그 운명을 게걸스레 탐하였다.","JPN":"その忌々しい呪いにより子どもたちが持って生まれたケモノの血は、事あるごとに子どもたちの運命を貪った。","ENG":"That unspeakable curse stirred the Beast Blood in their veins, endlessly gnawing at their fate.","TWN":"那難以言喻的詛咒，讓孩子們天生的野獸之血，在每一個瞬間都貪婪地吞噬著他們的命運。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"연옥에 묻힌 짐승은 아이들의 눈물과 한 그리고 피를 마심으로서 다시금 강림할 것을 예정하였으니.","JPN":"煉獄に埋められたケモノは子どもたちの涙と恨み、そして血を飲むことで再び降臨を図る。","ENG":"The Beasts buried in purgatory were fated to rise again, fed by the tears, sorrow, and blood of those children.","TWN":"被埋葬在煉獄中的野獸，藉由飲用孩子們的眼淚、遺憾和血液，再次降臨於世。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"죽지 않는 짐승과 싸우는 것은 우리 삼군문의 끝나지 않을 업이 되었다.","JPN":"かくして不死のケモノとの戦いは、我々三軍門の永遠の業となった。","ENG":"To battle the undying Beasts became the eternal burden of Trivanguard.","TWN":"與不死野獸戰鬥，成為我們三軍門永無止境的宿命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이 세계가 어찌 끝날 것 같은가, 관리자.","JPN":"この世界はどのような終わりを迎えると思うか、管理者。","ENG":"What do you think, Administrator? How will this world end?","TWN":"你認為這個世界會如何終結，管理者。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방금 자네가 말하지 않았나. 삼군문 중 누구도 범을 죽일 운명이 없었다고.","JPN":"先程君が言っただろう。三軍門の誰にも、虎を殺す運命の者はいなかったと。","ENG":"You just said it yourself. No one in Trivanguard was ever destined to kill the Tiger.","TWN":"你剛才不是說了嗎。三軍門中，沒有人有能殺死老虎的命運。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말이 사실이라면 우린 범을 막는 데 실패하고, 마왕의 좌를 내어준 뒤 세계는 멸망할 테지.","JPN":"その話が事実なら我々は虎を防ぐことに失敗し、やつは魔王になってこの世界を滅ぼすだろう。","ENG":"If that's true, then we'll fail to stop it. The throne of the Demon Lord will be claimed and the world will fall.","TWN":"如果這是真的，那我們將無法阻止老虎，並將魔王之位拱手讓人，世界將會滅亡。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그렇게 될 걸세. 좋든 싫든 범에게 상처 입힐 수 있는 건 삼군문 뿐이니 말이야.","JPN":"そうなるだろう。良くも悪くも虎に傷をつけられるのは三軍門のみだからな。","ENG":"That's how it'll go. Like it or not, we're the only ones who can even wound the Tiger.","TWN":"確實會如此。無論如何，只有三軍門能傷害老虎。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"헌데, 오늘 참으로 유별난 경험을 했어.","JPN":"しかし、今日は実に珍しい体験をした。","ENG":"But I had an unusual experience today.","TWN":"然而，我今天有了一次非常特殊的經歷。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"한 아이의 점괘를 보았는데, 땅내림의 피를 가졌음에도 짐승에게 죽을 운명이 아니었다네.","JPN":"ある子どもについて占いをしたら、チガカリの血を持っているにもかかわらず、ケモノに殺される運命ではなかったんだ。","ENG":"I read the fortune of a child born Earthbound, yet fate said nothing of death by the Beast.","TWN":"我看見了一個孩子的卜卦，他雖然擁有地脈之力之血，卻沒有死於野獸之手的命運。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"짐승의 피를 가졌음에도 짐승과 얽히지 않는 운명이라니. 모순이로군.","JPN":"ケモノの血を持ちながらケモノと関わらない運命とは、矛盾しているな。","ENG":"Born of Beast Blood, yet untouched by its fate? A contradiction.","TWN":"擁有野獸之血，卻與野獸無關的命運。這很矛盾。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"운명이란 건 힘을 주면 구부러지는 듯 하다가도 결국 제자리를 찾기 마련.","JPN":"運命とは、力を加えれば曲がるように見えても、結局はあるべき形へ戻るもの。","ENG":"Fate may bend under pressure, but it always snaps back.","TWN":"命運就像是，你用力拉扯時它好像會彎曲，但最終都會回到原位。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"어쩌면 그 모순이 우릴 도와줄 해답일지도 모르지.","JPN":"もしかすると、その矛盾が俺たちを救ってくれるかもしれんな。","ENG":"Maybe that contradiction is what'll break us through.","TWN":"或許那個矛盾，會是幫助我們的答案。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로 우리가 무엇을 하면 되겠나?","JPN":"これから私たちは何をすればいい？","ENG":"So then, what do we do?","TWN":"接下來我們該怎麼做？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"노릴 것이 달리 없다면, 그 모순을 노려보세.","JPN":"他に打開策がないのなら、その矛盾を狙ってみろ。","ENG":"If there's nothing else to aim for, let's aim for the contradiction.","TWN":"如果沒有其他目標，那就瞄準那個矛盾吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"머잖아 닥쳐올 종말의 벽 앞에 모든 수단을 준비하고…","JPN":"まもなく迫りくる終末の壁を前に、あらゆる手段を講じ……","ENG":"Prepare everything we can for the wall of apocalypse coming our way…","TWN":"在即將到來的末日之牆前，準備好所有手段…"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"한 점의 모순을 찾아 돌파하는 것이지.","JPN":"一点の矛盾を見つけ出し、突破するのだ。","ENG":"And find that single crack to break through it.","TWN":"找到那一點矛盾，並突破它。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"…굉장해. 장막 반경 10km 레드존을 반나절도 안돼서 단독으로 돌파하다니.","JPN":"……すごい。バリアの半径10kmのレッドゾーンを半日もかからないスピードで単独突破するなんて。","ENG":"…Incredible. You cleared a 10km-radius red zone alone in half a day.","TWN":"…太厲害了。不到半天的時間，就獨自突破了10公里半徑的紅區。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};